"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["44613"],{67983(s){s.exports=JSON.parse('{"tag":{"label":"upd","permalink":"/sysanalyst-kb.github.io/docs/tags/upd","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":1,"items":[{"id":"specialization/logistics-edo","title":"\u042D\u0414\u041E \u0438 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u043E\u0431\u043E\u0440\u043E\u0442 \u0432 \u043B\u043E\u0433\u0438\u0441\u0442\u0438\u043A\u0435","description":"\u042D\u0414\u041E (\u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u044B\u0439 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u043E\u0431\u043E\u0440\u043E\u0442) \u0432 \u043B\u043E\u0433\u0438\u0441\u0442\u0438\u043A\u0435 \u2014 \u043E\u0431\u043C\u0435\u043D \u0423\u041F\u0414, \u0430\u043A\u0442\u0430\u043C\u0438, \u0441\u0447\u0435\u0442\u0430\u043C\u0438-\u0444\u0430\u043A\u0442\u0443\u0440\u0430\u043C\u0438, \u0442\u0440\u0430\u043D\u0441\u043F\u043E\u0440\u0442\u043D\u044B\u043C\u0438 \u043D\u0430\u043A\u043B\u0430\u0434\u043D\u044B\u043C\u0438 \u043C\u0435\u0436\u0434\u0443 \u0443\u0447\u0430\u0441\u0442\u043D\u0438\u043A\u0430\u043C\u0438 (\u0433\u0440\u0443\u0437\u043E\u043E\u0442\u043F\u0440\u0430\u0432\u0438\u0442\u0435\u043B\u044C, \u043F\u0435\u0440\u0435\u0432\u043E\u0437\u0447\u0438\u043A, \u0433\u0440\u0443\u0437\u043E\u043F\u043E\u043B\u0443\u0447\u0430\u0442\u0435\u043B\u044C). \u0421 2021 \u0433\u043E\u0434\u0430 \u042D\u0422\u0420\u041D (\u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u0430\u044F \u0442\u0440\u0430\u043D\u0441\u043F\u043E\u0440\u0442\u043D\u0430\u044F \u043D\u0430\u043A\u043B\u0430\u0434\u043D\u0430\u044F) \u043E\u0431\u044F\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u0430 \u0434\u043B\u044F \u0433\u0440\u0443\u0437\u043E\u043F\u0435\u0440\u0435\u0432\u043E\u0437\u043E\u043A \u0432 \u0420\u0424. \u0423\u0447\u0430\u0441\u0442\u043D\u0438\u043A\u0438 \u043F\u043E\u0434\u043F\u0438\u0441\u044B\u0432\u0430\u044E\u0442 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u044B \u0423\u041A\u042D\u041F (\u0443\u0441\u0438\u043B\u0435\u043D\u043D\u0430\u044F \u043A\u0432\u0430\u043B\u0438\u0444\u0438\u0446\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u0430\u044F \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u0430\u044F \u043F\u043E\u0434\u043F\u0438\u0441\u044C) \u0447\u0435\u0440\u0435\u0437 \u043E\u043F\u0435\u0440\u0430\u0442\u043E\u0440\u043E\u0432 \u042D\u0414\u041E (\u0414\u0438\u0430\u0434\u043E\u043A, \u0421\u0411\u0418\u0421, \u041A\u043E\u043D\u0442\u0443\u0440). \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 \u0442\u0438\u043F\u044B \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u0432, \u0441\u0442\u0430\u0442\u0443\u0441\u043D\u0443\u044E \u043C\u043E\u0434\u0435\u043B\u044C, \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044E \u0441 \u043E\u043F\u0435\u0440\u0430\u0442\u043E\u0440\u0430\u043C\u0438 \u0438 TMS.","permalink":"/sysanalyst-kb.github.io/docs/specialization/logistics-edo"}],"unlisted":false}}')}}]);